"""
Parameterized generator for GH331_psycopg_1260.

Source PR:    https://github.com/psycopg/psycopg/pull/1260
Source Issue: N/A

Seed varies: renames 'after' identifier with suffix across seeds.

Bug: pre-PR state of workspace files contains the bug the PR fixes.
Fix: agent must replicate the PR's changes guided by spec.md.
"""
from __future__ import annotations

import os
from generators.base import TaskGenerator, GeneratedTask


class Generator(TaskGenerator):
    task_id = 'GH331_psycopg_1260'
    domain = "Real-World GitHub"
    difficulty = "medium"
    languages = ["python"]

    def generate(self, seed: int) -> GeneratedTask:
        tasks_dir = os.path.join(
            os.path.dirname(__file__), "..", "tasks", 'GH331_psycopg_1260'
        )
        with open(os.path.join(tasks_dir, "spec.md")) as f:
            spec_md = f.read()
        with open(os.path.join(tasks_dir, "brief.md")) as f:
            brief_md = f.read()

        files = self._base_workspace()
        # Apply seed-based renaming to prevent direct memorization
        suffixes = ["", "_alt", "_impl"]
        suffix = suffixes[seed % len(suffixes)]
        if suffix:
            for fpath in list(files.keys()):
                files[fpath] = files[fpath].replace('after', 'after' + suffix)
        # Deep parameterization — consistent cross-seed variation
        from generators.gh_deep_param import deep_rename_symbols, add_realistic_noise
        files = deep_rename_symbols(files, seed, strategy="mixed")
        files = add_realistic_noise(files, seed, noise_level=0.15)
        return GeneratedTask(
            task_id='GH331_psycopg_1260',
            seed=seed,
            spec_md=spec_md,
            brief_md=brief_md,
            expected={
                "seed": seed,
                "repo": 'psycopg/psycopg',
                "pr_number": 1260,
                "bug_fixed": True,
            },
            workspace_files=files,
            metadata={
                "difficulty": "medium",
                "category": "Real-World GitHub",
                "source_pr": "https://github.com/psycopg/psycopg/pull/1260",
            },
        )

    def _base_workspace(self) -> dict[str, str]:
        """Return the pre-PR (buggy) workspace files."""
        return {
            'docs/news.rst': '.. currentmodule:: psycopg\n\n.. index::\n    single: Release notes\n    single: News\n\n``psycopg`` release notes\n=========================\n\nCurrent release\n---------------\n\nPsycopg 3.3.3 (unreleased)\n^^^^^^^^^^^^^^^^^^^^^^^^^^\n\nRetain `Error.pgconn` when raising a single exception for multiple connection\nattempt errors (:ticket:`#1246`).\n\n\nPsycopg 3.3.2\n^^^^^^^^^^^^^\n\nFix race condition in adapters at startup (:ticket:`#1230`).\n\n\nPsycopg 3.3.1\n^^^^^^^^^^^^^\n\nFix iteration on server-side cursors (:ticket:`#1226`).\n\n\nPsycopg 3.3.0\n-------------\n\n.. rubric:: New top-level features\n\n- Add :ref:`template strings queries <template-strings>` (:ticket:`#1054`).\n- More flexible :ref:`composite adaptation<adapt-composite>`: it is now possible\n  to adapt Python objects to PostgreSQL composites and back even if they are not\n  sequences or if they take keyword arguments (:ticket:`#932`, :ticket:`#1202`).\n- Cursors are now iterators_, not just iterables_. This means you can call\n  `next`\\ ``(cur)`` or `anext`\\ ``(cur)``, which is useful as a :ref:`type-safe\n  expression <typing-fetchone>` (:ticket:`#1064`).\n- Add `Cursor.set_result()` and `Cursor.results()` to move across the result\n  sets of queries executed though `~Cursor.executemany()` or\n  `~Cursor.execute()` with multiple statements (:tickets:`#1080, #1170`).\n- Add :ref:`transaction-status` to report the status during and after a\n  `~Connection.transaction()` block (:ticket:`#969`).\n- Allow to change loaders using `~adapt.AdaptersMap.register_loader()` on\n  `Cursor.adapters` after a query result has been already returned\n  (:ticket:`#884`).\n\n.. rubric:: New libpq wrapper features\n\n- Add `pq.PGconn.used_gssapi` attribute and `Capabilities.has_used_gssapi()`\n  function (:ticket:`#1138`).\n- Add `ConnectionInfo.full_protocol_version` attribute,\n  `Capabilities.has_full_protocol_version()` function (:ticket:`#1079`).\n\n.. rubric:: Other changes\n\n- Disable default GSSAPI preferential connection in the binary package\n  (:ticket:`#1136`).\n\n  .. warning::\n\n    Please explicitly set the gssencmode_ connection parameter or the\n    :envvar:`PGGSSENCMODE` environment variable to interact reliably with the\n    GSSAPI.\n\n- Drop support for Python 3.8 (:ticket:`#976`) and 3.9 (:ticket:`#1056`).\n\n.. _iterators: https://docs.python.org/3/glossary.html#term-iterator\n.. _iterables: https://docs.python.org/3/glossary.html#term-iterable\n\n\nPsycopg 3.2.13\n^^^^^^^^^^^^^^\n\n- Show the host name in the error message in case of name resolution error\n  (:ticket:`#1205`).\n- Fix `Cursor.copy()` and `AsyncCursor.copy()` to hold the connection lock\n  for the entire operation, preventing concurrent access issues (:ticket:`#1210`).\n- Fix GSSAPI check with C extension built with libpq < v16 (:ticket:`#1216`).\n\n\nPsycopg 3.2.12\n^^^^^^^^^^^^^^\n\n- Allow copy to pass different types per column, as long as the database can\n  convert them. Regression introduced in 3.2.11 (:ticket:`#1192`).\n\n\nPsycopg 3.2.11\n^^^^^^^^^^^^^^\n\n- Fix spurious readiness flags in some of the wait functions (:ticket:`#1141`).\n- Fix high CPU usage using the ``wait_c`` function on Windows (:ticket:`#645`).\n- Fix bad data on error in binary copy (:ticket:`#1147`).\n- Respect `Copy.set_types()` in TEXT copy in C version, consistently with\n  the Python version (:ticket:`#1153`).\n- Don\'t raise warning, and don\'t leak resources, if a builtin function is used\n  as JSON dumper/loader function (:ticket:`#1165`).\n- Improve performance of Python conversion on results loading (:ticket:`#1155`).\n\n\n.. _psycopg-3.2.10:\n\nPsycopg 3.2.10\n^^^^^^^^^^^^^^\n\n- Fix `!TypeError` shadowing `~asyncio.CancelledError` upon task cancellation\n  during pipeline execution (:ticket:`#1005`).\n- Fix memory leak when lambda/local functions are used as argument for\n  `~.psycopg.types.json.set_json_dumps()`, `~.psycopg.types.json.set_json_loads()`\n  (:ticket:`#1108`).\n- Fix coordination of `~Cursor.executemany()` with other concurrent operations\n  on other cursors (:ticket:`#1130`).\n- Fix leak receiving notifications if the `~Connection.notifies()` generator\n  is not called (:ticket:`#1091`).\n\n  .. warning::\n\n    This bugfix required the introduction of a change in :ref:`notifies\n    reception <async-notify>` behaviour.\n\n    If a notification is received when a handler is registered via\n    `~Connection.add_notify_handler()` and the `~Connection.notifies()`\n    generator is not running the notification will not be yielded by the\n    generator. This is a behaviour similar to before `Psycopg 3.2.4`_, but\n    *notifications are not lost if no handler is registered*.\n\n    Using both the generator and handlers to receive notifications on the same\n    connection is therefore deprecated and will now generate a runtime\n    warning.\n\n- Add support for Python 3.14 (:ticket:`#1053`).\n- Fix `psycopg_binary.__version__`.\n- Raise a warning if a GSSAPI connection is obtained using the\n  ``gssencmode=prefer`` libpq default (see :ticket:`#1136`).\n\n  .. warning::\n\n    In a future Psycopg version the default in the binary package will be\n    changed to ``disable``. If you need to interact with the GSSAPI reliably\n    you should explicitly set the gssencmode_ parameter in the connection\n    string or the :envvar:`PGGSSENCMODE` environment variable to ``prefer`` or\n    ``require``.\n\n.. _gssencmode: https://www.postgresql.org/docs/current/libpq-connect.html#LIBPQ-CONNECT-GSSENCMODE\n\n\nPsycopg 3.2.9\n^^^^^^^^^^^^^\n\n- Revert the libpq included in the binary packages from conda forge to vcpkg\n  because GSS connection crashes (:ticket:`#1088`).\n\n\nPsycopg 3.2.8\n^^^^^^^^^^^^^\n\n- Fix `DateFromTicks` and `TimeFromTicks` return values to return a date and a\n  time referred to the UTC timezone rather than to the local timezone. For\n  consistency, `TimestampFromTicks` to return a datetime in UTC rather than in\n  the local timezone (:ticket:`#1058`).\n- Fix `~Cursor.rownumber` after using `~AsyncServerCursor.scroll()` on\n  `AsyncServerCursor` (:ticket:`#1066`).\n- Fix interval parsing with days or other parts and negative time in C module\n  (:ticket:`#1071`).\n- Don\'t process further connection attempts after Ctrl-C (:ticket:`#1077`).\n- Fix cursors to correctly iterate over rows even if their row factory\n  returns `None` (:ticket:`#1073`).\n- Fix `ConnectionInfo.port` when the port is specified as an empty string\n  (:ticket:`#1078`).\n- Report all the attempts error messages in the exception raised for a\n  connection failure (:ticket:`#1069`).\n- Improve logging on connection (:ticket:`#1085`).\n- Add support for PostgreSQL 18 libpq (:ticket:`#1082`).\n\n\nPsycopg 3.2.7\n^^^^^^^^^^^^^\n\n- Add SRID support to shapely dumpers/loaders (:ticket:`#1028`).\n- Add support for binary hstore (:ticket:`#1030`).\n\n\nPsycopg 3.2.6\n^^^^^^^^^^^^^\n\n- Fix connection semantic when using ``target_session_attrs=prefer-standby``\n  (:ticket:`#1021`).\n\n\nPsycopg 3.2.5\n^^^^^^^^^^^^^\n\n- 3x faster UUID loading thanks to C implementation (:tickets:`#447, #998`).\n\n\n.. _psycopg-3.2.4:\n\nPsycopg 3.2.4\n^^^^^^^^^^^^^\n\n- Don\'t lose notifies received whilst the `~Connection.notifies()` iterator\n  is not running (:ticket:`#962`).\n\n  .. warning::\n\n    If you were using notifications to bridge the time between issuing a LISTEN\n    on a channel and starting the iterator you might receive duplicate\n    notifications.\n\n- Make sure that the notifies callback is called during the use of the\n  `~Connection.notifies()` generator (:ticket:`#972`).\n- Raise the correct error returned by the database (such as `!AdminShutdown`\n  or `!IdleInTransactionSessionTimeout`) instead of a generic\n  `OperationalError` when a server error causes a client disconnection\n  (:ticket:`#988`).\n- Build macOS dependencies from sources instead using the Homebrew versions\n  in order to avoid problems with ``MACOSX_DEPLOYMENT_TARGET`` (:ticket:`#858`).\n- Bump libpq to 17.2 in Linux and macOS binary packages.\n- Bump libpq to 16.4 in Windows binary packages, using the `vcpkg library`__\n  (:ticket:`#966`).\n\n.. __: https://vcpkg.io/en/package/libpq\n\n\nPsycopg 3.2.3\n^^^^^^^^^^^^^\n\n- Release binary packages including PostgreSQL 17 libpq (:ticket:`#852`).\n\n\nPsycopg 3.2.2\n^^^^^^^^^^^^^\n\n- Drop `!TypeDef` specifications as string from public modules, as they cannot\n  be composed by users as `!typing` objects previously could (:ticket:`#860`).\n- Release Python 3.13 binary packages.\n\n\nPsycopg 3.2.1\n^^^^^^^^^^^^^\n\n- Fix packaging metadata breaking ``[c]``, ``[binary]`` dependencies\n  (:ticket:`#853`).\n\n\nPsycopg 3.2\n-----------\n\n.. rubric:: New top-level features\n\n- Add support for integer, floating point, boolean `NumPy scalar types`__\n  (:ticket:`#332`).\n- Add `!timeout` and `!stop_after` parameters to `Connection.notifies()`\n  (:ticket:`340`).\n- Allow dumpers to return `!None`, to be converted to NULL (:ticket:`#377`).\n- Add :ref:`raw-query-cursors` to execute queries using placeholders in\n  PostgreSQL format (`$1`, `$2`...) (:tickets:`#560, #839`).\n- Add `capabilities` object to :ref:`inspect the libpq capabilities\n  <capabilities>` (:ticket:`#772`).\n- Add `~rows.scalar_row` to return scalar values from a query (:ticket:`#723`).\n- Add `~Connection.cancel_safe()` for encrypted and non-blocking cancellation\n  when using libpq v17. Use such method internally to implement\n  `!KeyboardInterrupt` and `~cursor.copy` termination (:ticket:`#754`).\n- The `!context` parameter of `sql` objects `~sql.Composable.as_string()` and\n  `~sql.Composable.as_bytes()` methods is now optional (:ticket:`#716`).\n- Add `~Connection.set_autocommit()` on sync connections, and similar\n  transaction control methods available on the async connections.\n- Add a `size` parameter to `~Cursor.stream()` to enable results retrieval in\n  chunks instead of row-by-row (:ticket:`#794`).\n\n.. rubric:: New libpq wrapper features\n\n- Add support for libpq functions to close prepared statements and portals\n  introduced in libpq v17 (:ticket:`#603`).\n- Add support for libpq encrypted and non-blocking query cancellation\n  functions introduced in libpq v17 (:ticket:`#754`).\n- Add support for libpq function to retrieve results in chunks introduced in\n  libpq v17 (:ticket:`#793`).\n- Add support for libpq function to change role passwords introduced in\n  libpq v17 (:ticket:`#818`).\n\n.. rubric:: Other changes\n\n- Drop support for Python 3.7.\n- Prepared statements are now :ref:`compatible with PgBouncer <pgbouncer>`.\n  (:ticket:`#589`).\n- Disable receiving more than one result on the same cursor in pipeline mode,\n  to iterate through `~Cursor.nextset()`. The behaviour was different than\n  in non-pipeline mode and not totally reliable (:ticket:`#604`).\n  The `Cursor` now only preserves the results set of the last\n  `~Cursor.execute()`, consistently with non-pipeline mode.\n\n.. __: https://numpy.org/doc/stable/reference/arrays.scalars.html#built-in-scalar-types\n\n\nPsycopg 3.1.20\n^^^^^^^^^^^^^^\n\n- Use the simple query protocol to execute COMMIT/ROLLBACK when possible.\n  This should make querying the PgBouncer admin database easier\n  (:ticket:`#820`).\n- Avoid unneeded escaping checks and memory over-allocation in text copy\n  (:ticket:`#829`).\n- Bundle binary package with OpenSSL 3.3.x (:ticket:`#847`).\n- Drop macOS ARM64 binary packages for macOS versions before 14.0 and Python\n  before 3.10 (not for our choice but for the lack of available CI runners;\n  :ticket:`#858`)\n\n\nPsycopg 3.1.19\n^^^^^^^^^^^^^^\n\n- Fix unaligned access undefined behaviour in C extension (:ticket:`#734`).\n- Fix excessive stripping of error message prefixes (:ticket:`#752`).\n- Allow to specify the ``connect_timeout`` connection parameter as float\n  (:ticket:`#796`).\n- Improve COPY performance on macOS (:ticket:`#745`).\n\n\nPsycopg 3.1.18\n^^^^^^^^^^^^^^\n\n- Fix possible deadlock on pipeline exit (:ticket:`#685`).\n- Fix overflow loading large intervals in C module (:ticket:`#719`).\n- Fix compatibility with musl libc distributions affected by `CPython issue\n  #65821`__ (:ticket:`#725`).\n\n.. __: https://github.com/python/cpython/issues/65821\n\n\nPsycopg 3.1.17\n^^^^^^^^^^^^^^\n\n- Fix multiple connection attempts when a host name resolve to multiple\n  IP addresses (:ticket:`#699`).\n- Use `typing.Self` as a more correct return value annotation of context\n  managers and other self-returning methods (see :ticket:`#708`).\n\n\nPsycopg 3.1.16\n^^^^^^^^^^^^^^\n\n- Fix empty ports handling in async multiple connection attempts\n  (:ticket:`#703`).\n\n\nPsycopg 3.1.15\n^^^^^^^^^^^^^^\n\n- Fix use of ``service`` in connection string (regression in 3.1.13,\n  :ticket:`#694`).\n- Fix async connection to hosts resolving to multiple IP addresses (regression\n  in 3.1.13, :ticket:`#695`).\n- Respect the :envvar:`PGCONNECT_TIMEOUT` environment variable to determine\n  the connection timeout.\n\n\nPsycopg 3.1.14\n^^^^^^^^^^^^^^\n\n- Fix :ref:`interaction with gevent <gevent>` (:ticket:`#527`).\n- Add support for PyPy (:ticket:`#686`).\n\n.. _gevent: https://www.gevent.org/\n\n\nPsycopg 3.1.13\n^^^^^^^^^^^^^^\n\n- Raise `DataError` instead of whatever internal failure trying to dump a\n  `~datetime.time` object with with a `!tzinfo` specified as\n  `~zoneinfo.ZoneInfo` (ambiguous offset, see :ticket:`#652`).\n- Handle gracefully EINTR on signals instead of raising `InterruptedError`,\n  consistently with :pep:`475` guideline (:ticket:`#667`).\n- Fix support for connection strings with multiple hosts/ports and for the\n  ``load_balance_hosts`` connection parameter (:ticket:`#674`).\n- Fix memory leak receiving notifications in Python implementation\n  (:ticket:`#679`).\n\n\nPsycopg 3.1.12\n^^^^^^^^^^^^^^\n\n- Fix possible hanging if a connection is closed while querying (:ticket:`#608`).\n- Fix memory leak when `~register_*()` functions are called repeatedly\n  (:ticket:`#647`).\n- Release Python 3.12 binary packages.\n\n\nPsycopg 3.1.11\n^^^^^^^^^^^^^^\n\n- Avoid caching the parsing results of large queries to avoid excessive memory\n  usage (:ticket:`#628`).\n- Fix integer overflow in C/binary extension with OID > 2^31 (:ticket:`#630`).\n- Fix loading of intervals with days and months or years (:ticket:`#643`).\n- Work around excessive CPU usage on Windows (reported in :ticket:`#645`).\n- Fix building on Solaris and derivatives (:ticket:`#632`).\n- Fix possible lack of critical section guard in async\n  `~AsyncCursor.executemany()`.\n- Fix missing pipeline fetch in async `~AsyncCursor.scroll()`.\n- Build binary packages with libpq 15.4, which allows group-readable\n  permissions on the SSL certificate on the client (:ticket:`#528`).\n\n\nPsycopg 3.1.10\n^^^^^^^^^^^^^^\n\n- Allow JSON dumpers to dump `bytes` directly instead of `str`,\n  for better compatibility with libraries like orjson and msgspec\n  (:ticket:`#569`)\n- Fix prepared statement cache validation when exiting pipeline mode (or\n  `~Cursor.executemany()`) in case an error occurred within the pipeline\n  (:ticket:`#585`).\n- Fix `connect()` to avoid "leaking" an open `~pq.PGconn` attached to the\n  `OperationalError` in case of connection failure. `Error.pgconn` is now a\n  shallow copy of the real libpq connection, and the latter is closed before\n  the exception propagates (:ticket:`#565`).\n- Fix possible (ignored) exception on objects deletion (:ticket:`#591`).\n- Don\'t clobber a Python exception raised during COPY FROM with the resulting\n  `!QueryCanceled` raised as a consequence (:ticket:`#593`).\n- Fix resetting `Connection.read_only` and `~Connection.deferrable` to their\n  default value using `!None` (:ticket:`#612`).\n- Add support for Python 3.12.\n\n\nPsycopg 3.1.9\n^^^^^^^^^^^^^\n\n- Fix `TypeInfo.fetch()` using a connection in `!sql_ascii` encoding\n  (:ticket:`#503`).\n- Fix "filedescriptor out of range" using a large number of files open\n  in Python implementation (:ticket:`#532`).\n- Allow JSON dumpers to be registered on `!dict` or any other object, as was\n  possible in psycopg2 (:ticket:`#541`).\n- Fix canceling running queries on process interruption in async connections\n  (:ticket:`#543`).\n- Fix loading ROW values with different types in the same query using the\n  binary protocol (:ticket:`#545`).\n- Fix dumping recursive composite types (:ticket:`#547`).\n\n\nPsycopg 3.1.8\n^^^^^^^^^^^^^\n\n- Don\'t pollute server logs when types looked for by `TypeInfo.fetch()`\n  are not found (:ticket:`#473`).\n- Set `Cursor.rowcount` to the number of rows of each result set from\n  `~Cursor.executemany()` when called with `!returning=True` (:ticket:`#479`).\n- Fix `TypeInfo.fetch()` when used with `ClientCursor` (:ticket:`#484`).\n\n\nPsycopg 3.1.7\n^^^^^^^^^^^^^\n\n- Fix server-side cursors using row factories (:ticket:`#464`).\n\n\nPsycopg 3.1.6\n^^^^^^^^^^^^^\n\n- Fix `cursor.copy()` with cursors using row factories (:ticket:`#460`).\n\n\nPsycopg 3.1.5\n^^^^^^^^^^^^^\n\n- Fix array loading slowness compared to psycopg2 (:ticket:`#359`).\n- Improve performance around network communication (:ticket:`#414`).\n- Return `!bytes` instead of `!memoryview` from `pq.Encoding` methods\n  (:ticket:`#422`).\n- Fix `Cursor.rownumber` to return `!None` when the result has no row to fetch\n  (:ticket:`#437`).\n- Avoid error in Pyright caused by aliasing `!TypeAlias` (:ticket:`#439`).\n- Fix `Copy.set_types()` used with `varchar` and `name` types (:ticket:`#452`).\n- Improve performance using :ref:`row-factories` (:ticket:`#457`).\n\n\nPsycopg 3.1.4\n^^^^^^^^^^^^^\n\n- Include :ref:`error classes <sqlstate-exceptions>` defined in PostgreSQL 15.\n- Add support for Python 3.11 (:ticket:`#305`).\n- Build binary packages with libpq from PostgreSQL 15.0.\n\n\nPsycopg 3.1.3\n^^^^^^^^^^^^^\n\n- Restore the state of the connection if `Cursor.stream()` is terminated\n  prematurely (:ticket:`#382`).\n- Fix regression introduced in 3.1 with different named tuples mangling rules\n  for non-ascii attribute names (:ticket:`#386`).\n- Fix handling of queries with escaped percent signs (``%%``) in `ClientCursor`\n  (:ticket:`#399`).\n- Fix possible duplicated BEGIN statements emitted in pipeline mode\n  (:ticket:`#401`).\n\n\nPsycopg 3.1.2\n^^^^^^^^^^^^^\n\n- Fix handling of certain invalid time zones causing problems on Windows\n  (:ticket:`#371`).\n- Fix segfault occurring when a loader fails initialization (:ticket:`#372`).\n- Fix invalid SAVEPOINT issued when entering `Connection.transaction()` within\n  a pipeline using an implicit transaction (:ticket:`#374`).\n- Fix queries with repeated named parameters in `ClientCursor` (:ticket:`#378`).\n- Distribute macOS arm64 (Apple M1) binary packages (:ticket:`#344`).\n\n\nPsycopg 3.1.1\n^^^^^^^^^^^^^\n\n- Work around broken Homebrew installation of the libpq in a non-standard path\n  (:ticket:`#364`)\n- Fix possible "unrecognized service" error in async connection when no port\n  is specified (:ticket:`#366`).\n\n\nPsycopg 3.1\n-----------\n\n- Add :ref:`Pipeline mode <pipeline-mode>` (:ticket:`#74`).\n- Add :ref:`client-side-binding-cursors` (:ticket:`#101`).\n- Add `CockroachDB <https://www.cockroachlabs.com/>`__ support in `psycopg.crdb`\n  (:ticket:`#313`).\n- Add :ref:`Two-Phase Commit <two-phase-commit>` support (:ticket:`#72`).\n- Add :ref:`adapt-enum` (:ticket:`#274`).\n- Add ``returning`` parameter to `~Cursor.executemany()` to retrieve query\n  results (:ticket:`#164`).\n- `~Cursor.executemany()` performance improved by using batch mode internally\n  (:ticket:`#145`).\n- Add parameters to `~Cursor.copy()`.\n- Add :ref:`COPY Writer objects <copy-writers>`.\n- Resolve domain names asynchronously in `AsyncConnection.connect()`\n  (:ticket:`#259`).\n- Add `pq.PGconn.trace()` and related trace functions (:ticket:`#167`).\n- Add ``prepare_threshold`` parameter to `Connection` init (:ticket:`#200`).\n- Add ``cursor_factory`` parameter to `Connection` init.\n- Add `Error.pgconn` and `Error.pgresult` attributes (:ticket:`#242`).\n- Restrict queries to be `~typing.LiteralString` as per :pep:`675`\n  (:ticket:`#323`).\n- Add explicit type cast to values converted by `sql.Literal` (:ticket:`#205`).\n- Drop support for Python 3.6.\n\n\nPsycopg 3.0.17\n^^^^^^^^^^^^^^\n\n- Fix segfaults on fork on some Linux systems using `ctypes` implementation\n  (:ticket:`#300`).\n- Load bytea as bytes, not memoryview, using `ctypes` implementation.\n\n\nPsycopg 3.0.16\n^^^^^^^^^^^^^^\n\n- Fix missing `~Cursor.rowcount` after SHOW (:ticket:`#343`).\n- Add scripts to build macOS arm64 packages (:ticket:`#162`).\n\n\nPsycopg 3.0.15\n^^^^^^^^^^^^^^\n\n- Fix wrong escaping of unprintable chars in COPY (nonetheless correctly\n  interpreted by PostgreSQL).\n- Restore the connection to usable state after an error in `~Cursor.stream()`.\n- Raise `DataError` instead of `OverflowError` loading binary intervals\n  out-of-range.\n- Distribute ``manylinux2014`` wheel packages (:ticket:`#124`).\n\n\nPsycopg 3.0.14\n^^^^^^^^^^^^^^\n\n- Raise `DataError` dumping arrays of mixed types (:ticket:`#301`).\n- Fix handling of incorrect server results, with blank sqlstate (:ticket:`#303`).\n- Fix bad Float4 conversion on ppc64le/musllinux (:ticket:`#304`).\n\n\nPsycopg 3.0.13\n^^^^^^^^^^^^^^\n\n- Fix `Cursor.stream()` slowness (:ticket:`#286`).\n- Fix oid for lists of integers, which might cause the server choosing\n  bad plans (:ticket:`#293`).\n- Make `Connection.cancel()` on a closed connection a no-op instead of an\n  error.\n\n\nPsycopg 3.0.12\n^^^^^^^^^^^^^^\n\n- Allow `bytearray`/`memoryview` data too as `Copy.write()` input\n  (:ticket:`#254`).\n- Fix dumping `~enum.IntEnum` in text mode, Python implementation.\n\n\nPsycopg 3.0.11\n^^^^^^^^^^^^^^\n\n- Fix `DataError` loading arrays with dimensions information (:ticket:`#253`).\n- Fix hanging during COPY in case of memory error (:ticket:`#255`).\n- Fix error propagation from COPY worker thread (mentioned in :ticket:`#255`).\n\n\nPsycopg 3.0.10\n^^^^^^^^^^^^^^\n\n- Leave the connection in working state after interrupting a query with Ctrl-C\n  (:ticket:`#231`).\n- Fix `Cursor.description` after a COPY ... TO STDOUT operation\n  (:ticket:`#235`).\n- Fix building on FreeBSD and likely other BSD flavours (:ticket:`#241`).\n\n\nPsycopg 3.0.9\n^^^^^^^^^^^^^\n\n- Set `Error.sqlstate` when an unknown code is received (:ticket:`#225`).\n- Add the `!tzdata` package as a dependency on Windows in order to handle time\n  zones (:ticket:`#223`).\n\n\nPsycopg 3.0.8\n^^^^^^^^^^^^^\n\n- Decode connection errors in the ``client_encoding`` specified in the\n  connection string, if available (:ticket:`#194`).\n- Fix possible warnings in objects deletion on interpreter shutdown\n  (:ticket:`#198`).\n- Don\'t leave connections in ACTIVE state in case of error during COPY ... TO\n  STDOUT (:ticket:`#203`).\n\n\nPsycopg 3.0.7\n^^^^^^^^^^^^^\n\n- Fix crash in `~Cursor.executemany()` with no input sequence\n  (:ticket:`#179`).\n- Fix wrong `~Cursor.rowcount` after an `~Cursor.executemany()` returning no\n  rows (:ticket:`#178`).\n\n\nPsycopg 3.0.6\n^^^^^^^^^^^^^\n\n- Allow to use `Cursor.description` if the connection is closed\n  (:ticket:`#172`).\n- Don\'t raise exceptions on `ServerCursor.close()` if the connection is closed\n  (:ticket:`#173`).\n- Fail on `Connection.cursor()` if the connection is closed (:ticket:`#174`).\n- Raise `ProgrammingError` if out-of-order exit from transaction contexts is\n  detected (:tickets:`#176, #177`).\n- Add `!CHECK_STANDBY` value to `~pq.ConnStatus` enum.\n\n\nPsycopg 3.0.5\n^^^^^^^^^^^^^\n\n- Fix possible "Too many open files" OS error, reported on macOS but possible\n  on other platforms too (:ticket:`#158`).\n- Don\'t clobber exceptions if a transaction block exit with error and rollback\n  fails (:ticket:`#165`).\n\n\nPsycopg 3.0.4\n^^^^^^^^^^^^^\n\n- Allow to use the module with strict strings comparison (:ticket:`#147`).\n- Fix segfault on Python 3.6 running in ``-W error`` mode, related to\n  `!backport.zoneinfo` (:ticket:`#109`).\n  <https://github.com/pganssle/zoneinfo/issues/109>`__.\n- Build binary package with libpq versions not affected by `CVE-2021-23222\n  <https://www.postgresql.org/support/security/CVE-2021-23222/>`__\n  (:ticket:`#149`).\n\n\nPsycopg 3.0.3\n^^^^^^^^^^^^^\n\n- Release musllinux binary packages, compatible with Alpine Linux\n  (:ticket:`#141`).\n- Reduce size of binary package by stripping debug symbols (:ticket:`#142`).\n- Include typing information in the `!psycopg_binary` package.\n\n\nPsycopg 3.0.2\n^^^^^^^^^^^^^\n\n- Fix type hint for `sql.SQL.join()` (:ticket:`#127`).\n- Fix type hint for `Connection.notifies()` (:ticket:`#128`).\n- Fix call to `MultiRange.__setitem__()` with a non-iterable value and a\n  slice, now raising a `TypeError` (:ticket:`#129`).\n- Fix disable cursors methods after close() (:ticket:`#125`).\n\n\nPsycopg 3.0.1\n^^^^^^^^^^^^^\n\n- Fix use of the wrong dumper reusing cursors with the same query but different\n  parameter types (:ticket:`#112`).\n\n\nPsycopg 3.0\n-----------\n\nFirst stable release. Changed from 3.0b1:\n\n- Add :ref:`adapt-shapely` (:ticket:`#80`).\n- Add :ref:`adapt-multirange` (:ticket:`#75`).\n- Add `pq.__build_version__` constant.\n- Don\'t use the extended protocol with COPY, (:tickets:`#78, #82`).\n- Add ``context`` parameter to `~Connection.connect()` (:ticket:`#83`).\n- Fix selection of dumper by oid after `~Copy.set_types()`.\n- Drop `!Connection.client_encoding`. Use `ConnectionInfo.encoding` to read\n  it, and a :sql:`SET` statement to change it.\n- Add binary packages for Python 3.10 (:ticket:`#103`).\n\n\nPsycopg 3.0b1\n^^^^^^^^^^^^^\n\n- First public release on PyPI.\n',
            'psycopg/psycopg/_cursor_base.py': '"""\nPsycopg BaseCursor object\n"""\n\n# Copyright (C) 2020 The Psycopg Team\n\nfrom __future__ import annotations\n\nfrom typing import TYPE_CHECKING, Any, Generic, NoReturn\nfrom weakref import ReferenceType, ref\nfrom functools import partial\nfrom collections.abc import Iterable, Sequence\n\nfrom . import adapt\nfrom . import errors as e\nfrom . import pq\nfrom .abc import ConnectionType, Loader, Params, PQGen, Query\nfrom .rows import Row, RowMaker\nfrom ._column import Column\nfrom ._compat import Template\nfrom .pq.misc import connection_summary\nfrom ._queries import PostgresClientQuery, PostgresQuery\nfrom ._preparing import Prepare\nfrom .generators import execute, fetch, send\nfrom ._capabilities import capabilities\n\nif TYPE_CHECKING:\n    from .abc import Transformer\n    from .pq.abc import PGconn, PGresult\n\nTEXT = pq.Format.TEXT\nBINARY = pq.Format.BINARY\n\nEMPTY_QUERY = pq.ExecStatus.EMPTY_QUERY\nCOMMAND_OK = pq.ExecStatus.COMMAND_OK\nTUPLES_OK = pq.ExecStatus.TUPLES_OK\nCOPY_OUT = pq.ExecStatus.COPY_OUT\nCOPY_IN = pq.ExecStatus.COPY_IN\nCOPY_BOTH = pq.ExecStatus.COPY_BOTH\nFATAL_ERROR = pq.ExecStatus.FATAL_ERROR\nSINGLE_TUPLE = pq.ExecStatus.SINGLE_TUPLE\nTUPLES_CHUNK = pq.ExecStatus.TUPLES_CHUNK\nPIPELINE_ABORTED = pq.ExecStatus.PIPELINE_ABORTED\n\nACTIVE = pq.TransactionStatus.ACTIVE\n\n\nclass BaseCursor(Generic[ConnectionType, Row]):\n    __slots__ = """\n        _conn format _adapters arraysize _closed _results pgresult _pos\n        _iresult _rowcount _query _tx _last_query _row_factory _make_row\n        _pgconn _execmany_returning\n        __weakref__\n        """.split()\n\n    _tx: Transformer\n    _make_row: RowMaker[Row]\n    _pgconn: PGconn\n    _query_cls: type[PostgresQuery] = PostgresQuery\n\n    def __init__(self, connection: ConnectionType):\n        self._conn = connection\n        self.format = TEXT\n        self._pgconn = connection.pgconn\n        self._adapters = adapt.AdaptersMap(connection.adapters)\n        self.arraysize = 1\n        self._closed = False\n        self._last_query: Query | None = None\n        self._reset()\n\n        # Set up a callback to allow changing loaders on already returned result.\n        self._adapters._register_loader_callback = partial(\n            self._loaders_changed, ref(self)\n        )\n\n    def _reset(self, reset_query: bool = True) -> None:\n        self._results: list[PGresult] = []\n        self.pgresult: PGresult | None = None\n        self._pos = 0\n        self._iresult = 0\n        self._rowcount = -1\n        self._query: PostgresQuery | None\n        # None if executemany() not executing, True/False according to returning state\n        self._execmany_returning: bool | None = None\n        if reset_query:\n            self._query = None\n\n    def __repr__(self) -> str:\n        cls = f"{self.__class__.__module__}.{self.__class__.__qualname__}"\n        info = connection_summary(self._pgconn)\n        if self._closed:\n            status = "closed"\n        elif self.pgresult:\n            status = pq.ExecStatus(self.pgresult.status).name\n        else:\n            status = "no result"\n        return f"<{cls} [{status}] {info} at 0x{id(self):x}>"\n\n    @property\n    def connection(self) -> ConnectionType:\n        """The connection this cursor is using."""\n        return self._conn\n\n    @property\n    def adapters(self) -> adapt.AdaptersMap:\n        return self._adapters\n\n    @property\n    def closed(self) -> bool:\n        """`True` if the cursor is closed."""\n        return self._closed\n\n    @property\n    def description(self) -> list[Column] | None:\n        """\n        A list of `Column` objects describing the current resultset.\n\n        `!None` if the current resultset didn\'t return tuples.\n        """\n        res = self.pgresult\n\n        # We return columns if we have nfields, but also if we don\'t but\n        # the query said we got tuples (mostly to handle the super useful\n        # query "SELECT ;"\n        if res and (\n            res.nfields\n            or res.status == TUPLES_OK\n            or res.status == SINGLE_TUPLE\n            or res.status == TUPLES_CHUNK\n        ):\n            return [Column(self, i) for i in range(res.nfields)]\n        else:\n            return None\n\n    @property\n    def rowcount(self) -> int:\n        """\n        Number of records affected by the operation that produced\n        the current result set.\n        """\n        return self._rowcount\n\n    @property\n    def rownumber(self) -> int | None:\n        """Index of the next row to fetch in the current result set.\n\n        `!None` if there is no result to fetch.\n        """\n        tuples = self.pgresult and self.pgresult.status == TUPLES_OK\n        return self._pos if tuples else None\n\n    def setinputsizes(self, sizes: Sequence[Any]) -> None:\n        # no-op\n        pass\n\n    def setoutputsize(self, size: Any, column: int | None = None) -> None:\n        # no-op\n        pass\n\n    def nextset(self) -> bool | None:\n        """\n        Move to the result set of the next query executed through `executemany()`\n        or to the next result set if `execute()` returned more than one.\n\n        Return `!True` if a new result is available, which will be the one\n        methods `!fetch*()` will operate on.\n        """\n        if self._iresult < len(self._results) - 1:\n            self._select_current_result(self._iresult + 1)\n            return True\n        else:\n            return None\n\n    @property\n    def statusmessage(self) -> str | None:\n        """\n        The status tag of the current result set.\n\n        `!None` if the cursor doesn\'t have a result available.\n        """\n        msg = self.pgresult.command_status if self.pgresult else None\n        return msg.decode() if msg else None\n\n    def _make_row_maker(self) -> RowMaker[Row]:\n        raise NotImplementedError\n\n    #\n    # Generators for the high level operations on the cursor\n    #\n    # Like for sync/async connections, these are implemented as generators\n    # so that different concurrency strategies (threads,asyncio) can use their\n    # own way of waiting (or better, `connection.wait()`).\n    #\n\n    def _execute_gen(\n        self,\n        query: Query,\n        params: Params | None = None,\n        *,\n        prepare: bool | None = None,\n        binary: bool | None = None,\n    ) -> PQGen[None]:\n        """Generator implementing `Cursor.execute()`."""\n        yield from self._start_query(query)\n        pgq = self._convert_query(query, params)\n        yield from self._maybe_prepare_gen(pgq, prepare=prepare, binary=binary)\n        if self._conn._pipeline:\n            yield from self._conn._pipeline._communicate_gen()\n\n        self._last_query = query\n        yield from self._conn._prepared.maintain_gen(self._conn)\n\n    def _executemany_gen_pipeline(\n        self, query: Query, params_seq: Iterable[Params], returning: bool\n    ) -> PQGen[None]:\n        """\n        Generator implementing `Cursor.executemany()` with pipelines available.\n        """\n        pipeline = self._conn._pipeline\n        assert pipeline\n\n        yield from self._start_query(query)\n        if not returning:\n            self._rowcount = 0\n\n        assert self._execmany_returning is None\n        self._execmany_returning = returning\n\n        first = True\n        for params in params_seq:\n            if first:\n                pgq = self._convert_query(query, params)\n                self._query = pgq\n                first = False\n            else:\n                pgq.dump(params)\n\n            yield from self._maybe_prepare_gen(pgq, prepare=True)\n            yield from pipeline._communicate_gen()\n\n        self._last_query = query\n\n        if returning:\n            yield from pipeline._fetch_gen(flush=True)\n\n        yield from self._conn._prepared.maintain_gen(self._conn)\n\n    def _executemany_gen_no_pipeline(\n        self, query: Query, params_seq: Iterable[Params], returning: bool\n    ) -> PQGen[None]:\n        """\n        Generator implementing `Cursor.executemany()` with pipelines not available.\n        """\n        yield from self._start_query(query)\n        if not returning:\n            self._rowcount = 0\n\n        assert self._execmany_returning is None\n        self._execmany_returning = returning\n\n        first = True\n        for params in params_seq:\n            if first:\n                pgq = self._convert_query(query, params)\n                self._query = pgq\n                first = False\n            else:\n                pgq.dump(params)\n\n            yield from self._maybe_prepare_gen(pgq, prepare=True)\n\n        self._last_query = query\n        yield from self._conn._prepared.maintain_gen(self._conn)\n\n    def _maybe_prepare_gen(\n        self,\n        pgq: PostgresQuery,\n        *,\n        prepare: bool | None = None,\n        binary: bool | None = None,\n    ) -> PQGen[None]:\n        # Check if the query is prepared or needs preparing\n        prep, name = self._get_prepared(pgq, prepare)\n        if prep is Prepare.NO:\n            # The query must be executed without preparing\n            self._execute_send(pgq, binary=binary)\n        else:\n            # If the query is not already prepared, prepare it.\n            if prep is Prepare.SHOULD:\n                self._send_prepare(name, pgq)\n                if not self._conn._pipeline:\n                    (result,) = yield from execute(self._pgconn)\n                    if result.status == FATAL_ERROR:\n                        raise e.error_from_result(result, encoding=self._encoding)\n            # Then execute it.\n            self._send_query_prepared(name, pgq, binary=binary)\n\n        # Update the prepare state of the query.\n        # If an operation requires to flush our prepared statements cache,\n        # it will be added to the maintenance commands to execute later.\n        key = self._conn._prepared.maybe_add_to_cache(pgq, prep, name)\n\n        if self._conn._pipeline:\n            queued = None\n            if key is not None:\n                queued = (key, prep, name)\n            self._conn._pipeline.result_queue.append((self, queued))\n            return\n\n        # run the query\n        results = yield from execute(self._pgconn)\n\n        if key is not None:\n            self._conn._prepared.validate(key, prep, name, results)\n\n        self._check_results(results)\n        self._set_results(results)\n\n    def _get_prepared(\n        self, pgq: PostgresQuery, prepare: bool | None = None\n    ) -> tuple[Prepare, bytes]:\n        return self._conn._prepared.get(pgq, prepare)\n\n    def _stream_send_gen(\n        self,\n        query: Query,\n        params: Params | None = None,\n        *,\n        binary: bool | None = None,\n        size: int,\n    ) -> PQGen[None]:\n        """Generator to send the query for `Cursor.stream()`."""\n        yield from self._start_query(query)\n        pgq = self._convert_query(query, params)\n        self._execute_send(pgq, binary=binary, force_extended=True)\n        if size < 1:\n            raise ValueError("size must be >= 1")\n        elif size == 1:\n            self._pgconn.set_single_row_mode()\n        else:\n            capabilities.has_stream_chunked(check=True)\n            self._pgconn.set_chunked_rows_mode(size)\n        self._last_query = query\n        yield from send(self._pgconn)\n\n    def _stream_fetchone_gen(self, first: bool) -> PQGen[PGresult | None]:\n        res: PGresult | None = yield from fetch(self._pgconn)\n        if res is None:\n            return None\n\n        status = res.status\n        if status == SINGLE_TUPLE or status == TUPLES_CHUNK:\n            self.pgresult = res\n            self._tx.set_pgresult(res, set_loaders=first)\n            if first:\n                self._make_row = self._make_row_maker()\n            return res\n\n        elif status == TUPLES_OK or status == COMMAND_OK:\n            # End of single row results\n            while res:\n                res = yield from fetch(self._pgconn)\n            if status != TUPLES_OK:\n                raise e.ProgrammingError(\n                    "the operation in stream() didn\'t produce a result"\n                )\n            return None\n\n        else:\n            # Errors, unexpected values\n            return self._raise_for_result(res)\n\n    def _start_query(self, query: Query | None = None) -> PQGen[None]:\n        """Generator to start the processing of a query.\n\n        It is implemented as generator because it may send additional queries,\n        such as `begin`.\n        """\n        if self.closed:\n            raise e.InterfaceError("the cursor is closed")\n\n        self._reset()\n        if not self._last_query or (self._last_query is not query):\n            self._last_query = None\n            self._tx = adapt.Transformer(self)\n        yield from self._conn._start_query()\n\n    def _start_copy_gen(\n        self, statement: Query, params: Params | None = None\n    ) -> PQGen[None]:\n        """Generator implementing sending a command for `Cursor.copy()."""\n\n        # The connection gets in an unrecoverable state if we attempt COPY in\n        # pipeline mode. Forbid it explicitly.\n        if self._conn._pipeline:\n            raise e.NotSupportedError("COPY cannot be used in pipeline mode")\n\n        yield from self._start_query()\n\n        # Merge the params client-side\n        if params or isinstance(statement, Template):\n            pgq = PostgresClientQuery(self._tx)\n            pgq.convert(statement, params)\n            statement = pgq.query\n\n        query = self._convert_query(statement)\n\n        self._execute_send(query, binary=False)\n        if len(results := (yield from execute(self._pgconn))) != 1:\n            raise e.ProgrammingError("COPY cannot be mixed with other operations")\n\n        self._check_copy_result(results[0])\n        self._set_results(results)\n\n    def _execute_send(\n        self,\n        query: PostgresQuery,\n        *,\n        force_extended: bool = False,\n        binary: bool | None = None,\n    ) -> None:\n        """\n        Implement part of execute() before waiting common to sync and async.\n\n        This is not a generator, but a normal non-blocking function.\n        """\n        if binary is None:\n            fmt = self.format\n        else:\n            fmt = BINARY if binary else TEXT\n\n        self._query = query\n\n        if self._conn._pipeline:\n            # In pipeline mode always use PQsendQueryParams - see #314\n            # Multiple statements in the same query are not allowed anyway.\n            self._conn._pipeline.command_queue.append(\n                partial(\n                    self._pgconn.send_query_params,\n                    query.query,\n                    query.params,\n                    param_formats=query.formats,\n                    param_types=query.types,\n                    result_format=fmt,\n                )\n            )\n        elif force_extended or query.params or fmt == BINARY:\n            self._pgconn.send_query_params(\n                query.query,\n                query.params,\n                param_formats=query.formats,\n                param_types=query.types,\n                result_format=fmt,\n            )\n        else:\n            # If we can, let\'s use simple query protocol,\n            # as it can execute more than one statement in a single query.\n            self._pgconn.send_query(query.query)\n\n    def _convert_query(\n        self, query: Query, params: Params | None = None\n    ) -> PostgresQuery:\n        pgq = self._query_cls(self._tx)\n        pgq.convert(query, params)\n        return pgq\n\n    def _check_results(self, results: list[PGresult]) -> None:\n        """\n        Verify that the results of a query are valid.\n\n        Verify that the query returned at least one result and that they all\n        represent a valid result from the database.\n        """\n        if not results:\n            raise e.InternalError("got no result from the query")\n\n        for res in results:\n            if (\n                (status := res.status) != TUPLES_OK\n                and status != COMMAND_OK\n                and status != EMPTY_QUERY\n                and status != COPY_BOTH\n            ):\n                self._raise_for_result(res)\n\n    def _raise_for_result(self, result: PGresult) -> NoReturn:\n        """\n        Raise an appropriate error message for an unexpected database result\n        """\n        if (status := result.status) == FATAL_ERROR:\n            raise e.error_from_result(result, encoding=self._encoding)\n        elif status == PIPELINE_ABORTED:\n            raise e.PipelineAborted("pipeline aborted")\n        elif status == COPY_IN or status == COPY_OUT or status == COPY_BOTH:\n            raise e.ProgrammingError(\n                "COPY cannot be used with this method; use copy() instead"\n            )\n        else:\n            raise e.InternalError(\n                "unexpected result status from query:" f" {pq.ExecStatus(status).name}"\n            )\n\n    def _select_current_result(self, i: int, format: pq.Format | None = None) -> None:\n        """\n        Select one of the results in the cursor as the active one.\n        """\n        self._iresult = i\n        res = self.pgresult = self._results[i]\n\n        # Note: the only reason to override format is to correctly set\n        # binary loaders on server-side cursors, because send_describe_portal\n        # only returns a text result.\n        self._tx.set_pgresult(res, format=format)\n\n        self._pos = 0\n\n        if res.status == TUPLES_OK:\n            self._rowcount = self.pgresult.ntuples\n\n        # COPY_OUT has never info about nrows. We need such result for the\n        # columns in order to return a `description`, but not overwrite the\n        # cursor rowcount (which was set by the Copy object).\n        elif res.status != COPY_OUT:\n            nrows = self.pgresult.command_tuples\n            self._rowcount = nrows if nrows is not None else -1\n\n        self._make_row = self._make_row_maker()\n\n    def _set_results(self, results: list[PGresult]) -> None:\n        if self._execmany_returning is None:\n            # Received from execute()\n            self._results[:] = results\n            self._select_current_result(0)\n        # Received from executemany()\n        elif self._execmany_returning:\n            first_batch = not self._results\n            self._results.extend(results)\n            if first_batch:\n                self._select_current_result(0)\n        else:\n            # In non-returning case, set rowcount to the cumulated number of\n            # rows of executed queries.\n            for res in results:\n                self._rowcount += res.command_tuples or 0\n\n    @classmethod\n    def _loaders_changed(\n        cls, wself: ReferenceType[BaseCursor[Any, Any]], oid: int, loader: type[Loader]\n    ) -> None:\n        """Callback called when self.adapters.set_loaders is called.\n\n        Allow to change the loaders after the results have been returned already.\n        """\n        if not (self := wself()):\n            return\n\n        # Replace the transformer with a new one, restore the current state.\n        self._tx = adapt.Transformer(self)\n        pos = self._pos\n        if self._iresult < len(self._results):\n            self._select_current_result(self._iresult)\n            self._pos = pos\n\n    def _send_prepare(self, name: bytes, query: PostgresQuery) -> None:\n        if self._conn._pipeline:\n            self._conn._pipeline.command_queue.append(\n                partial(\n                    self._pgconn.send_prepare,\n                    name,\n                    query.query,\n                    param_types=query.types,\n                )\n            )\n            self._conn._pipeline.result_queue.append(None)\n        else:\n            self._pgconn.send_prepare(name, query.query, param_types=query.types)\n\n    def _send_query_prepared(\n        self, name: bytes, pgq: PostgresQuery, *, binary: bool | None = None\n    ) -> None:\n        if binary is None:\n            fmt = self.format\n        else:\n            fmt = BINARY if binary else TEXT\n\n        if self._conn._pipeline:\n            self._conn._pipeline.command_queue.append(\n                partial(\n                    self._pgconn.send_query_prepared,\n                    name,\n                    pgq.params,\n                    param_formats=pgq.formats,\n                    result_format=fmt,\n                )\n            )\n        else:\n            self._pgconn.send_query_prepared(\n                name, pgq.params, param_formats=pgq.formats, result_format=fmt\n            )\n\n    def _check_result_for_fetch(self) -> PGresult:\n        if self.closed:\n            raise e.InterfaceError("the cursor is closed")\n\n        if not (res := self.pgresult):\n            raise e.ProgrammingError("no result available")\n\n        if (status := res.status) == TUPLES_OK:\n            return res\n        elif status == FATAL_ERROR:\n            raise e.error_from_result(res, encoding=self._encoding)\n        elif status == PIPELINE_ABORTED:\n            raise e.PipelineAborted("pipeline aborted")\n        else:\n            if res.command_status:\n                detail = f" (command status: {res.command_status.decode()})"\n            else:\n                try:\n                    status_name = pq.ExecStatus(status).name\n                except ValueError:\n                    status_name = f"{status} - unknown"\n                detail = f" (result status: {status_name})"\n            raise e.ProgrammingError(\n                f"the last operation didn\'t produce records{detail}"\n            )\n\n    def _check_copy_result(self, result: PGresult) -> None:\n        """\n        Check that the value returned in a copy() operation is a legit COPY.\n        """\n        status = result.status\n        if status == COPY_IN or status == COPY_OUT:\n            return\n        elif status == FATAL_ERROR:\n            raise e.error_from_result(result, encoding=self._encoding)\n        else:\n            raise e.ProgrammingError(\n                "copy() should be used only with COPY ... TO STDOUT or COPY ..."\n                f" FROM STDIN statements, got {pq.ExecStatus(status).name}"\n            )\n\n    def _scroll(self, value: int, mode: str) -> None:\n        res = self._check_result_for_fetch()\n        if mode == "relative":\n            newpos = self._pos + value\n        elif mode == "absolute":\n            newpos = value\n        else:\n            raise ValueError(f"bad mode: {mode}. It should be \'relative\' or \'absolute\'")\n        if not 0 <= newpos < res.ntuples:\n            raise IndexError("position out of bound")\n        self._pos = newpos\n\n    def _close(self) -> None:\n        """Non-blocking part of closing. Common to sync/async."""\n        # Don\'t reset the query because it may be useful to investigate after\n        # an error.\n        self._reset(reset_query=False)\n        self._closed = True\n\n    @property\n    def _encoding(self) -> str:\n        return self._pgconn._encoding\n',
        }
